"""HLD Advanced Topics: Data Structures for Big Data, Vector Databases, Time Series Databases — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def bigdata_ds_lesson() -> Lesson:
    return Lesson(id="hld-bigdata-ds", number=125, title="Data Structures for Big Data",
        focus=("Bloom filter","HyperLogLog","Count-Min Sketch","skip list","trie","geohash"),
        overview="Probabilistic and space-efficient data structures that solve massive-scale problems elegantly.",
        patterns=(), badge="HLD Advanced", tasks=(
        quiz("bd-1","What is a Bloom filter?","hard",("big-data",),("A security protocol that authenticates both client and server during the handshake","A replication strategy where writes go to any node and conflicts are resolved on read","A probabilistic structure: may say 'possibly yes' but never 'definitely no' — false positives, no false negatives","A sharding approach that distributes cached entries across nodes by consistent hashing"),2,"Space-efficient membership test. Used for cache penetration prevention, spam filtering, spell checking."),
        quiz("bd-2","What is a HyperLogLog?","hard",("big-data",),("A replication technique that mirrors hot cache entries across multiple nodes for availability","A resilience pattern that isolates failures in one subsystem from propagating to others","A DNS-based technique that distributes queries across multiple authoritative servers","A probabilistic algorithm for cardinality estimation (count distinct) using O(1) space with ~2% error"),3,"Count 1 billion unique visitors with only 12KB. Redis PFADD/PFCOUNT implements this."),
        quiz("bd-3","What is a Count-Min Sketch?","hard",("big-data",),("A partitioning strategy that splits data based on a hash of the composite primary key","A deployment strategy that gradually shifts traffic from the old version to the new one","A probabilistic frequency table: estimates how many times an element has been seen, with possible overcount","A communication pattern where services exchange messages through a centralized broker"),2,"CMS: O(1) space per element. Used for heavy hitters, top-K queries, and frequency estimation."),
        quiz("bd-4","What is a skip list?","hard",("big-data",),("A pattern where incoming requests are buffered and processed in priority-ordered batches","A warming strategy that pre-loads data based on access frequency from the previous day","A scheduling algorithm that assigns tasks to workers based on estimated completion time","A layered sorted linked list providing O(log n) search, insert, delete — used by Redis Sorted Sets"),3,"Skip lists: probabilistic balancing without tree rotations. Simpler to implement than balanced BSTs."),
        quiz("bd-5","What is a trie (prefix tree)?","medium",("big-data",),("A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A tree where each edge represents a character — O(k) lookup for k-length strings. Used for autocomplete","A serialization format that reduces cache entry size through schema-aware compression","A persistence mechanism that snapshots the cache state to disk for crash recovery"),1,"Tries: prefix-based search, autocomplete, IP routing tables. Space-efficient for shared prefixes."),
        quiz("bd-6","What is a geohash?","hard",("big-data",),("Encodes 2D lat/lng into a 1D string by interleaving bits — nearby points share prefixes for range queries","A connection management approach that limits concurrent sessions to prevent overload","A protocol that batches multiple requests into a single TCP segment for efficiency","A flow control mechanism that prevents the sender from overwhelming the receiver"),0,"Geohash 'gc7x' means NYC area. Longer string = more precision. Used for proximity search."),
        quiz("bd-7","What is a Merkle tree?","hard",("big-data",),("A replication technique that synchronously mirrors writes to a standby for zero data loss","A hash tree where each leaf is a hash of data and each node is a hash of its children — detects differences efficiently","A schema design pattern that embeds frequently accessed data to avoid join overhead","A process that periodically reconciles state between systems to detect and fix drift"),1,"Merkle trees: compare two datasets by comparing root hashes. Used in Git, blockchain, Cassandra repair."),
        quiz("bd-8","What is a T-digest?","hard",("big-data",),("A connection management approach that pins clients to specific backend instances","A coordination service that uses ephemeral nodes for automatic failure detection","An algorithm for accurate estimation of quantiles (p50, p99) from streaming data with bounded memory","A technique where the server pre-fetches resources based on predicted client needs"),2,"T-digest: compute accurate percentiles over billions of data points with only kilobytes of state."),
        quiz("bd-9","What is a quotient filter?","hard",("big-data",),("A prefetching algorithm that predicts future access patterns from recent query history","A space-efficient probabilistic data structure for set membership, supporting deletion (unlike Bloom filters)","A load shedding strategy that drops low-priority requests when resource utilization is high","A technique that partitions workload across worker pools based on resource requirements"),1,"Quotient filters: similar to Bloom but support deletion and have better cache performance."),
        quiz("bd-10","What is a Cuckoo filter?","hard",("big-data",),("A probabilistic data structure supporting membership testing AND deletion with better space efficiency than Bloom","A consensus protocol that uses a rotating leader to distribute write coordination load","A transaction isolation level that prevents phantom reads using predicate locking","A consistency model where reads from any replica are guaranteed to be monotonically fresh"),0,"Cuckoo filters: 2 hash functions, elements can be relocated. Supports delete. Often better than Bloom in practice."),
        quiz("bd-11","What is an R-tree?","hard",("big-data",),("An index maintenance operation that rebuilds fragmented pages for better scan performance","A spatial index for multi-dimensional data (bounding rectangles) — used for geographic range queries","A membership protocol where nodes periodically exchange state with random cluster peers","A clock synchronization technique that uses NTP with bounded drift for ordering events"),1,"R-trees: used by PostGIS for spatial queries like 'find all restaurants within this bounding box'."),
        quiz("bd-12","What is a roaring bitmap?","hard",("big-data",),("A cache coherence protocol that broadcasts invalidation messages to all cache tiers","A transport layer optimization that reduces round-trip overhead using multiplexing","A compressed bitmap using a hybrid of arrays, bitmaps, and run-length encoding for efficient set operations","A data structure that stores cache metadata compactly using probabilistic counting"),2,"Roaring bitmaps: much more space-efficient than plain bitmaps. Used in Elasticsearch, Apache Druid."),
        quiz("bd-13","What is consistent hashing with bounded loads?","hard",("big-data",),("Variant where each node has a max load cap — overflow keys spill to next node, preventing hotspots","Standard consistent hashing across multiple service instances","A routing strategy that directs traffic based on geographic proximity of the client","A partitioning algorithm that assigns data based on a hash of the geographic region"),0,"Bounded load: Google's algorithm ensures no node exceeds (1+ε) × average load."),
        quiz("bd-14","What is a DAWG (Directed Acyclic Word Graph)?","hard",("big-data",),("An eviction algorithm that considers both recency and frequency when selecting victims","A trie that shares suffixes too (not just prefixes) — more compact for dictionary storage","A backup mechanism that captures incremental changes since the last full snapshot","A monitoring tool that tracks query execution plans and identifies slow running queries"),1,"DAWG: minimal automaton for a set of strings. More compact than trie. Used in spell checkers."),
        quiz("bd-15","What is SimHash?","hard",("big-data",),("A data pipeline stage that transforms and enriches events before writing to storage","A storage engine optimization that pre-sorts data on disk for sequential access patterns","A locality-sensitive hash: similar documents produce similar hashes — used for near-duplicate detection","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool"),2,"SimHash: detect duplicate web pages, similar articles, or plagiarism at web scale."),
        quiz("bd-16","What is a ring buffer?","medium",("big-data",),("A testing approach that injects controlled failures to verify system recovery behavior","A fixed-size circular buffer where new data overwrites oldest — used for recent events, metrics, logs","A state synchronization approach that reconciles differences using Merkle tree comparison","A query optimization strategy that rewrites subqueries into more efficient join patterns"),1,"Ring buffers: bounded memory, O(1) insert, natural sliding window. Used in Disruptor, kernel networking."),
        quiz("bd-17","What is the MinHash algorithm?","hard",("big-data",),("A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests","Estimates Jaccard similarity between sets using random hash functions — used for near-duplicate detection at scale","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","A congestion avoidance algorithm that dynamically adjusts the transmission window"),1,"MinHash: compute approximate set similarity without comparing full sets. O(k) per comparison."),
        quiz("bd-18","What is a segment tree?","hard",("big-data",),("A B-tree variant — commonly used in production environments","A tree for efficient range queries (sum, min, max) with O(log n) update and query on intervals","A hash function — commonly used in production environments","A linked list — commonly used in production environments"),1,"Segment trees: used in competitive programming and databases for range aggregation queries."),
        quiz("bd-19","What is a Fenwick tree (Binary Indexed Tree)?","hard",("big-data",),("A linked list — commonly used in production environments","A hash function — commonly used in production environments","A B-tree — commonly used in production environments","A tree for efficient prefix sum queries and point updates in O(log n) — simpler than segment trees"),3,"Fenwick trees: compact representation for cumulative frequency tables. Less memory than segment trees."),
        quiz("bd-20","What is the difference between exact and approximate algorithms for big data?","medium",("big-data",),("Exact is always faster — commonly used in production environments","Approximate is always wrong with automatic failover support","No difference — commonly used in production environments","Exact algorithms use O(n) space; approximate use O(1) or O(log n) with bounded error — tradeoff accuracy for scalability"),3,"At scale, exact cardinality (hash set) is impossible. HyperLogLog: 12KB vs 1GB for exact, ~2% error."),
    ))

def vector_db_lesson() -> Lesson:
    return Lesson(id="hld-vector-db", number=126, title="Vector Databases",
        focus=("embeddings","ANN search","HNSW","IVF","similarity metrics","RAG"),
        overview="Vector databases power AI search, recommendations, and RAG. Know embedding storage and ANN algorithms.",
        patterns=(), badge="HLD Advanced", tasks=(
        quiz("vec-1","What is a vector database?","medium",("vector-db",),("A relational database — commonly used in production environments","A database optimized for storing, indexing, and querying high-dimensional vectors (embeddings)","A key-value store — commonly used in production environments","A graph database — commonly used in production environments"),1,"Vector DBs (Pinecone, Weaviate, Milvus, Qdrant) support similarity search on embeddings."),
        quiz("vec-2","What is an embedding?","medium",("vector-db",),("A token — commonly used in production environments","A dense numerical vector representing the semantic meaning of text, images, or other data","A URL — commonly used in production environments","A hash — commonly used in production environments"),1,"Embeddings: 'cat' → [0.2, 0.8, ...]. Similar concepts have similar vectors (close in space)."),
        quiz("vec-3","What is approximate nearest neighbor (ANN) search?","hard",("vector-db",),("Exact search — commonly used in production environments","A hash function — commonly used in production environments","Finding vectors close to a query vector in high-dimensional space, sacrificing some accuracy for speed","A sorting algorithm — commonly used in production environments"),2,"Exact KNN is O(n). ANN is ~O(log n) with >95% recall. Essential for real-time vector search."),
        quiz("vec-4","What is HNSW (Hierarchical Navigable Small World)?","hard",("vector-db",),("A B-tree variant — commonly used in production environments","A graph-based ANN algorithm with multiple layers — fast, high recall, used by most vector DBs","A hash function — commonly used in production environments","A database index — commonly used in production environments"),1,"HNSW: navigate from coarse top layer to fine bottom layer. O(log n) search. Best quality/speed tradeoff."),
        quiz("vec-5","What is IVF (Inverted File Index) for vectors?","hard",("vector-db",),("A text index — commonly used in production environments","Clusters vectors into partitions; search only the nearest clusters instead of all vectors","A hash table — commonly used in production environments","A B-tree — commonly used in production environments"),1,"IVF: K-means clustering → search only top-k clusters. Fast but needs periodic re-clustering."),
        quiz("vec-6","What is the difference between cosine similarity and Euclidean distance?","hard",("vector-db",),("Same thing — commonly used in production environments","Cosine measures angle (direction); Euclidean measures straight-line distance (magnitude matters)","Euclidean is always better with automatic failover support","Cosine is faster — commonly used in production environments"),1,"Cosine similarity: good for text (direction matters). Euclidean: good when magnitude is meaningful."),
        quiz("vec-7","What is RAG (Retrieval Augmented Generation)?","medium",("vector-db",),("A database type — commonly used in production environments","A fine-tuning method — commonly used in production environments","A training technique — commonly used in production environments","Retrieve relevant documents via vector search, then feed them as context to an LLM for grounded answers"),3,"RAG: embed docs → store in vector DB → query → retrieve top-K → inject into LLM prompt → generate answer."),
        quiz("vec-8","What is the curse of dimensionality?","hard",("vector-db",),("A storage issue — commonly used in production environments","In high dimensions, all points become roughly equidistant, making exact distance measures less meaningful","A programming error — commonly used in production environments","A network problem — commonly used in production environments"),1,"At 1000+ dimensions, distance becomes less discriminative. Dimensionality reduction (PCA) can help."),
        quiz("vec-9","What is product quantization?","hard",("vector-db",),("A database index — commonly used in production environments","A compression technique: split vectors into sub-vectors, quantize each independently, reducing storage and compute","Multiplication — commonly used in production environments","A hash function — commonly used in production environments"),1,"PQ: 768-dim vector → 96 sub-vectors of 8 dims each → 96 bytes instead of 3072. Approximate but fast."),
        quiz("vec-10","What is the difference between Pinecone and Milvus?","hard",("vector-db",),("Pinecone is open-source — commonly used in production environments","Milvus is managed only — commonly used in production environments","Same thing — commonly used in production environments","Pinecone: fully managed cloud service. Milvus: open-source, self-hosted, more customizable"),3,"Pinecone: zero-ops. Milvus: full control, GPU acceleration, multiple index types."),
        quiz("vec-11","What is hybrid search in vector databases?","hard",("vector-db",),("A replication strategy — commonly used in production environments","Two databases — commonly used in production environments","A sharding technique — commonly used in production environments","Combining vector similarity search with traditional keyword/filter search for better results"),3,"Hybrid: vector search for semantic relevance + keyword filters (category, date) for precision."),
        quiz("vec-12","What is the role of metadata filtering in vector search?","medium",("vector-db",),("No role — commonly used in production environments","Pre-filter or post-filter vectors by metadata (tags, categories, dates) before/after similarity computation","A caching strategy — commonly used in production environments","An indexing technique — commonly used in production environments"),1,"Pre-filtering: narrow candidates first, then vector search. More efficient for selective queries."),
        quiz("vec-13","What is the embedding dimension tradeoff?","hard",("vector-db",),("Higher dimensions capture more nuance but use more storage, slower search, and need more training data","Dimension doesn't matter — commonly used in production environments","Higher is always better — commonly used in production environments","Lower is always better — commonly used in production environments"),0,"OpenAI ada-002: 1536 dims. MiniLM: 384 dims. Smaller models are faster but less expressive."),
        quiz("vec-14","How do you update vectors in a vector database?","medium",("vector-db",),("Delete and re-insert: most vector indexes (HNSW, IVF) don't support efficient in-place updates","SQL UPDATE — commonly used in production environments","In-place update — commonly used in production environments","Modify directly — commonly used in production environments"),0,"Vector DBs often use a delete+insert pattern. Some support upsert for convenience."),
        quiz("vec-15","What is the distance metric inner product?","hard",("vector-db",),("Dot product of two vectors — equivalent to cosine similarity when vectors are normalized","A hash function — commonly used in production environments","A Euclidean variant — commonly used in production environments","Same as cosine — commonly used in production environments"),0,"For normalized vectors: inner product = cosine similarity. Many models pre-normalize embeddings."),
        quiz("vec-16","What is the ScaNN algorithm?","hard",("vector-db",),("A database — commonly used in production environments","A hash function — commonly used in production environments","Google's ANN algorithm using learned quantization and asymmetric hashing for state-of-the-art speed/recall","A B-tree — commonly used in production environments"),2,"ScaNN: anisotropic vector quantization. Among the fastest ANN algorithms. Used in Google Search."),
        quiz("vec-17","How do vector databases handle scale?","hard",("vector-db",),("Single node — commonly used in production environments","Sharding vectors across nodes + replicas for read scaling + in-memory indexes with disk spillover","No scaling needed — commonly used in production environments","Just add RAM — commonly used in production environments"),1,"Shard by ID or by vector cluster. Scatter-gather for cross-shard queries. Replicas for read throughput."),
        quiz("vec-18","What is the re-ranking pattern in vector search?","hard",("vector-db",),("Sorting results — commonly used in production environments","A caching strategy — commonly used in production environments","Retrieve top-K candidates with fast ANN, then re-rank with a more expensive cross-encoder model for precision","An indexing technique — commonly used in production environments"),2,"Two-stage: fast retrieval (bi-encoder + ANN) → precise re-ranking (cross-encoder). Balances speed and quality."),
        quiz("vec-19","What is the embedding update challenge?","hard",("vector-db",),("No challenge — commonly used in production environments","When the embedding model changes, ALL vectors must be re-computed and re-indexed — expensive at scale","Embeddings are fixed — commonly used in production environments","Auto-updates — commonly used in production environments"),1,"Model upgrade: re-embed entire corpus. Versioned indexes or gradual migration needed."),
        quiz("vec-20","What is multi-modal search with vector databases?","hard",("vector-db",),("Searching across different data types (text, images, audio) using a shared embedding space (CLIP, etc.)","Text search only — commonly used in production environments","A database feature — commonly used in production environments","A caching strategy — commonly used in production environments"),0,"CLIP embeds images and text into the same vector space. Search images with text queries and vice versa."),
    ))

def timeseries_db_lesson() -> Lesson:
    return Lesson(id="hld-timeseries-db", number=127, title="Time Series Databases",
        focus=("InfluxDB","TimescaleDB","Prometheus","downsampling","retention","compression"),
        overview="Time-series databases handle metrics, IoT, and financial data at massive scale. Know their internals.",
        patterns=(), badge="HLD Advanced", tasks=(
        quiz("ts-1","What is a time-series database optimized for?","medium",("timeseries",),("User profiles — commonly used in production environments","Full-text search — commonly used in production environments","Graph traversal — commonly used in production environments","Append-heavy workloads with timestamp-ordered data: metrics, IoT, financial, and event data"),3,"TSDB: optimized for high write throughput, time-range queries, and automatic data retention."),
        quiz("ts-2","What is the difference between InfluxDB and TimescaleDB?","hard",("timeseries",),("TimescaleDB is standalone for improved throughput","InfluxDB uses SQL — commonly used in production environments","Same thing — commonly used in production environments","InfluxDB: custom engine, Flux query language. TimescaleDB: PostgreSQL extension, uses SQL"),3,"TimescaleDB: full PostgreSQL compatibility + time-series optimizations. InfluxDB: purpose-built, custom query."),
        quiz("ts-3","What is downsampling in time-series?","medium",("timeseries",),("Compressing data — commonly used in production environments","Reducing resolution — commonly used in production environments","Aggregating high-resolution data into lower-resolution summaries (1-second → 1-minute averages)","Deleting data — commonly used in production environments"),2,"Keep 1s resolution for 24h, 1m for 30d, 1h for 1y. Reduces storage while preserving trends."),
        quiz("ts-4","What is data retention policy?","medium",("timeseries",),("A backup schedule — commonly used in production environments","A replication setting — commonly used in production environments","Never delete — commonly used in production environments","Automatically deleting data older than a threshold to manage storage costs"),3,"Retention: keep raw data for 30d, downsampled for 1y, delete after. Automates lifecycle management."),
        quiz("ts-5","What is Prometheus and what is it used for?","medium",("timeseries",),("A monitoring and alerting toolkit that collects metrics via pull model and stores as time-series","A database — commonly used in production environments","A message queue — commonly used in production environments","A cache — commonly used in production environments"),0,"Prometheus: scrapes /metrics endpoints, stores time-series, evaluates alert rules, integrates with Grafana."),
        quiz("ts-6","What is the pull vs push model for metrics collection?","hard",("timeseries",),("Same thing — commonly used in production environments","Pull (Prometheus): server scrapes targets. Push (Graphite, InfluxDB): targets send metrics to server","Pull is always better — commonly used in production environments","Push is always better — commonly used in production environments"),1,"Pull: easier service discovery, no metric loss on target crash. Push: better for short-lived jobs, firewalled envs."),
        quiz("ts-7","What is columnar storage and why does it matter for time-series?","hard",("timeseries",),("A caching technique — commonly used in production environments","Row storage — commonly used in production environments","Same as row storage — commonly used in production environments","Storing data column-by-column enables better compression and faster aggregation queries"),3,"Columnar: compress timestamps together (delta encoding), values together (gorilla compression). 10-100x smaller."),
        quiz("ts-8","What is Gorilla compression for time-series?","hard",("timeseries",),("Facebook's compression for timestamps (delta-of-delta) and values (XOR) — ~12 bytes per data point to ~1.37 bytes","ZIP compression — commonly used in production environments","A hash function — commonly used in production environments","A sorting algorithm — commonly used in production environments"),0,"Gorilla: timestamps compress via delta-of-delta. Float values compress via XOR with previous. Massive savings."),
        quiz("ts-9","What is a time-series tag/label?","medium",("timeseries",),("A category — commonly used in production environments","A data value — commonly used in production environments","Metadata key-value pairs identifying a metric series (host=server1, region=us-east, metric=cpu_usage)","A timestamp — commonly used in production environments"),2,"Tags define the cardinality of time-series. High-cardinality tags (user_id) can explode storage."),
        quiz("ts-10","What is the cardinality problem in time-series?","hard",("timeseries",),("Too many unique tag combinations create too many series, overwhelming storage and index","A network issue — commonly used in production environments","Too many values — commonly used in production environments","Not enough data — commonly used in production environments"),0,"1000 hosts × 100 metrics × 10 regions = 1M series. Each series has its own index entry. Cardinality explosion."),
        quiz("ts-11","What is a chunk/block in time-series storage?","hard",("timeseries",),("A fixed time window of data compressed and stored as a single unit (e.g., 2-hour Prometheus block)","A database row — commonly used in production environments","A partition — commonly used in production environments","A cache entry — commonly used in production environments"),0,"Chunks: immutable compressed blocks. Active chunk in memory, older chunks on disk. Append-only within chunk."),
        quiz("ts-12","What is the difference between metric and event time-series?","medium",("timeseries",),("Events are regular — commonly used in production environments","Same thing — commonly used in production environments","Metrics are events — commonly used in production environments","Metrics: regular interval readings (CPU every 10s). Events: irregular occurrences (login, error, purchase)"),3,"Metrics: fixed rate, predictable. Events: variable rate, unpredictable. Different storage optimizations."),
        quiz("ts-13","What is PromQL?","hard",("timeseries",),("A database — commonly used in production environments","Prometheus Query Language: rate(), histogram_quantile(), aggregation by labels for monitoring queries","A REST API — commonly used in production environments","SQL — commonly used in production environments"),1,"PromQL: rate(http_requests_total[5m]): per-second request rate over 5 minutes. Powerful for monitoring."),
        quiz("ts-14","What is a recording rule in Prometheus?","hard",("timeseries",),("A replication rule — commonly used in production environments","A backup rule — commonly used in production environments","A retention rule — commonly used in production environments","Pre-compute expensive PromQL queries and save results as new time-series — improves dashboard performance"),3,"Recording rules: compute once, store result. Dashboards read the pre-computed series instead of re-computing."),
        quiz("ts-15","What is the WAL in time-series databases?","hard",("timeseries",),("A backup — commonly used in production environments","An index type — commonly used in production environments","Write-Ahead Log ensures recent data survives crashes — data is buffered in WAL before compaction into blocks","A query optimizer — commonly used in production environments"),2,"WAL: crash recovery for the current active block. On restart, replay WAL to rebuild in-memory state."),
        quiz("ts-16","What is a continuous aggregate in TimescaleDB?","hard",("timeseries",),("A replication feature — commonly used in production environments","A cache — commonly used in production environments","An automatically maintained materialized view that incrementally aggregates new data as it arrives","A regular view — commonly used in production environments"),2,"Continuous aggregates: real-time materialized views. New data auto-aggregated without full recompute."),
        quiz("ts-17","What is the difference between Prometheus and Thanos/Cortex?","hard",("timeseries",),("Thanos/Cortex add long-term storage, global query view, and horizontal scaling on top of Prometheus","Same thing — commonly used in production environments","Cortex is deprecated — commonly used in production environments","Thanos replaces Prometheus with automatic failover support"),0,"Prometheus: single instance. Thanos: object storage backend, cross-cluster queries, unlimited retention."),
        quiz("ts-18","How does QuestDB achieve high write throughput?","hard",("timeseries",),("Standard PostgreSQL — commonly used in production environments","Single-threaded — commonly used in production environments","In-memory only — commonly used in production environments","Memory-mapped files, column-oriented storage, SIMD instructions, and zero-copy ingestion"),3,"QuestDB: millions of rows/sec ingestion. Uses SIMD for vectorized operations on time-series data."),
        quiz("ts-19","What is the exemplar feature in Prometheus?","hard",("timeseries",),("A sample value — commonly used in production environments","Links a metric data point to a specific trace ID, bridging metrics and distributed tracing","A label — commonly used in production environments","A recording rule — commonly used in production environments"),1,"Exemplars: click on a latency spike → see the exact trace that caused it. Metrics → traces correlation."),
        quiz("ts-20","When should you NOT use a time-series database?","medium",("timeseries",),("When data is large — commonly used in production environments","For non-time-ordered data, complex JOINs, transactions, or general-purpose application data","When you have time data — commonly used in production environments","Never — commonly used in production environments"),1,"TSDB: not for user profiles, orders, or relational data. Use PostgreSQL for general-purpose, TSDB for metrics."),
    ))
